# GitHub GraphQL API v4

The GraphQL API provides a single endpoint that returns exactly the data you request. Instead of hitting multiple REST endpoints, you compose a query that fetches nested resources in one request.

## Single Endpoint

All GraphQL requests go to `POST https://api.github.com/graphql` with a JSON body containing your query.

```bash
curl -X POST \
  -H "Authorization: Bearer $GITHUB_TOKEN" \
  -H "Content-Type: application/json" \
  -d '{"query": "{ viewer { login name } }"}' \
  https://api.github.com/graphql
```

## Basic Query

```graphql
query {
  repository(owner: "octokit", name: "rest.js") {
    name
    description
    stargazerCount
    defaultBranchRef {
      name
    }
    issues(first: 5, states: OPEN, orderBy: {field: CREATED_AT, direction: DESC}) {
      totalCount
      nodes {
        number
        title
        author { login }
        labels(first: 5) {
          nodes { name color }
        }
      }
    }
  }
}
```

```javascript
import { graphql } from "@octokit/graphql";

const graphqlWithAuth = graphql.defaults({
  headers: { authorization: `token ${process.env.GITHUB_TOKEN}` },
});

const { repository } = await graphqlWithAuth(`
  query($owner: String!, $name: String!) {
    repository(owner: $owner, name: $name) {
      name
      stargazerCount
      issues(first: 10, states: OPEN) {
        totalCount
        nodes { number title }
        pageInfo { hasNextPage endCursor }
      }
    }
  }
`, { owner: "octokit", name: "rest.js" });
```

## Mutations

Write operations use mutations:

```graphql
mutation($input: CreateIssueInput!) {
  createIssue(input: $input) {
    issue {
      number
      url
      title
    }
  }
}
```

```javascript
const { createIssue } = await graphqlWithAuth(`
  mutation($input: CreateIssueInput!) {
    createIssue(input: $input) {
      issue { number url title }
    }
  }
`, {
  input: {
    repositoryId: "R_abc123",
    title: "Bug: login fails",
    body: "Steps to reproduce...",
    labelIds: ["LA_abc123"],
  },
});
```

## Schema Introspection

```graphql
# Discover available types
query {
  __schema {
    types {
      name
      kind
      description
    }
  }
}

# Explore a specific type
query {
  __type(name: "Repository") {
    name
    fields {
      name
      type { name kind }
      description
    }
  }
}
```

Use the GitHub GraphQL Explorer at `https://docs.github.com/en/graphql/overview/explorer` for interactive schema exploration.

## Connections (Pagination)

Relationships use the Relay connection pattern. See [[github/pagination]] for cursor-based traversal.

```graphql
query($cursor: String) {
  repository(owner: "octokit", name: "rest.js") {
    issues(first: 100, after: $cursor) {
      totalCount
      pageInfo {
        hasNextPage
        endCursor
      }
      nodes {
        number
        title
      }
    }
  }
}
```

## Fragments

Reuse field selections across queries:

```graphql
fragment IssueFields on Issue {
  number
  title
  state
  author { login }
  createdAt
}

query {
  repository(owner: "octokit", name: "rest.js") {
    open: issues(first: 5, states: OPEN) {
      nodes { ...IssueFields }
    }
    closed: issues(first: 5, states: CLOSED) {
      nodes { ...IssueFields }
    }
  }
}
```

## Rate Limiting

GraphQL uses a point-based system (not request count). See [[github/rate-limits]] for details.

```graphql
query {
  rateLimit {
    limit
    cost
    remaining
    resetAt
  }
}
```
